// TAPD Keepalive Script
// Loads cookies, hits the workspace dashboard to refresh server-side session,
// then saves the new cookies back to tapd_cookies.json.
// Run periodically (every 1-2 days) to keep login alive indefinitely.
//
// Exit codes:
//   0 = success (cookies refreshed)
//   1 = cookie invalid / login expired (need re-login)
//   2 = script error (network, etc.)

import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const WORKSPACE_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WORKSPACE_DIR, 'tapd_cookies.json');
const STORAGE_FILE = path.join(WORKSPACE_DIR, 'tapd_storage.json');
const STATE_FILE = path.join(WORKSPACE_DIR, 'memory', 'tapd-keepalive-state.json');

const STEALTH_INIT = () => {
  delete navigator.webdriver;
  Object.defineProperty(navigator, 'webdriver', { get: () => false });
  Object.defineProperty(navigator, 'plugins', { get: () => [1, 2, 3, 4, 5] });
  Object.defineProperty(navigator, 'languages', { get: () => ['zh-CN', 'zh'] });
  Object.defineProperty(navigator, 'hardwareConcurrency', { get: () => 8 });
  window.chrome = { runtime: {}, loadTimes: function () {}, csi: function () {}, app: {} };
};

function log(msg) {
  console.log(`[${new Date().toISOString()}] ${msg}`);
}

function writeState(state) {
  try {
    fs.mkdirSync(path.dirname(STATE_FILE), { recursive: true });
    fs.writeFileSync(STATE_FILE, JSON.stringify(state, null, 2));
  } catch (e) {
    console.error('Failed to write state:', e.message);
  }
}

async function main() {
  if (!fs.existsSync(COOKIES_FILE)) {
    log(`ERROR: cookies file not found: ${COOKIES_FILE}`);
    writeState({ ok: false, error: 'cookies_missing', at: new Date().toISOString() });
    process.exit(1);
  }

  const oldCookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));
  log(`Loaded ${oldCookies.length} cookies`);

  const browser = await chromium.launch({
    headless: true,
    args: ['--no-sandbox', '--disable-blink-features=AutomationControlled'],
  });
  const ctx = await browser.newContext({
    locale: 'zh-CN',
    viewport: { width: 1920, height: 1080 },
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/125.0.0.0 Safari/537.36',
  });
  await ctx.addCookies(oldCookies);
  const page = await ctx.newPage();
  await page.addInitScript(STEALTH_INIT);

  try {
    log('Visiting workspace dashboard...');
    const resp = await page.goto('https://www.tapd.cn/31253609/', {
      waitUntil: 'domcontentloaded',
      timeout: 30000,
    });
    await page.waitForTimeout(3000);

    const url = page.url();
    const title = await page.title();
    const status = resp?.status();
    log(`HTTP ${status} | url=${url} | title=${title}`);

    if (url.includes('login') || title.includes('登录') || title.includes('WAF')) {
      log('❌ Session EXPIRED - need re-login');
      writeState({
        ok: false,
        error: 'session_expired',
        at: new Date().toISOString(),
        finalUrl: url,
        title,
      });
      await browser.close();
      process.exit(1);
    }

    // Bonus: also poke story-list to make sure deep nav still works
    await page.goto('https://www.tapd.cn/tapd_fe/31253609/story/list', {
      waitUntil: 'domcontentloaded',
      timeout: 30000,
    }).catch(() => {});
    await page.waitForTimeout(2000);

    // Save refreshed cookies
    const newCookies = await ctx.cookies();
    const newStorage = await ctx.storageState();

    fs.writeFileSync(COOKIES_FILE, JSON.stringify(newCookies, null, 2));
    fs.writeFileSync(STORAGE_FILE, JSON.stringify(newStorage, null, 2));

    // Find tapdsession expiry for state
    const tapdsession = newCookies.find((c) => c.name === 'tapdsession');
    const exp = tapdsession?.expires > 0
      ? new Date(tapdsession.expires * 1000).toISOString()
      : 'session';

    log(`✅ Refreshed ${newCookies.length} cookies | tapdsession exp: ${exp}`);
    writeState({
      ok: true,
      at: new Date().toISOString(),
      cookieCount: newCookies.length,
      tapdsessionExpires: exp,
      title,
    });

    await browser.close();
    process.exit(0);
  } catch (e) {
    log(`ERROR: ${e.message}`);
    writeState({ ok: false, error: e.message, at: new Date().toISOString() });
    try { await browser.close(); } catch {}
    process.exit(2);
  }
}

