// Reset the Feishu direct session for the owner.
// Backs up sessions.json, removes the target session entry, archives transcript files.

import fs from 'fs';
import path from 'path';
import os from 'os';

const SESSION_KEY = 'agent:main:feishu:direct:ou_6509d346e8d50ef882f89c436e6c977f';
const SESSIONS_DIR = path.join(os.homedir(), '.openclaw', 'agents', 'main', 'sessions');
const SESSIONS_FILE = path.join(SESSIONS_DIR, 'sessions.json');
const ARCHIVE_DIR = path.join(SESSIONS_DIR, 'archive');
const LOG_FILE = path.join(os.homedir(), '.openclaw', 'workspace', 'memory', 'session-reset-log.txt');

function ts() { return new Date().toISOString().replace('T', ' ').slice(0, 19); }
function log(msg) {
  const line = `[${ts()}] ${msg}`;
  console.log(line);
  try {
    fs.mkdirSync(path.dirname(LOG_FILE), { recursive: true });
    fs.appendFileSync(LOG_FILE, line + '\n');
  } catch {}
}

function main() {
  log(`Reset triggered for: ${SESSION_KEY}`);

  if (!fs.existsSync(SESSIONS_FILE)) {
    log(`ERROR: sessions.json not found at ${SESSIONS_FILE}`);
    process.exit(1);
  }

  // Backup
  const stamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
  const backup = `${SESSIONS_FILE}.bak-${stamp}`;
  fs.copyFileSync(SESSIONS_FILE, backup);
  log(`Backed up sessions.json → ${path.basename(backup)}`);

  // Parse
  const raw = fs.readFileSync(SESSIONS_FILE, 'utf8');
  let json;
  try {
    json = JSON.parse(raw);
  } catch (e) {
    log(`ERROR: failed to parse sessions.json: ${e.message}`);
    process.exit(2);
  }

  // Handle both flat-object and { sessions: {} } shapes
  let store, parent;
  if (json && typeof json === 'object' && json.sessions && typeof json.sessions === 'object' && !Array.isArray(json.sessions)) {
    store = json.sessions;
    parent = json;
  } else {
    store = json;
    parent = null;
  }

  if (!store[SESSION_KEY]) {
    log(`Session key not found: ${SESSION_KEY}`);
    log(`Available keys (${Object.keys(store).length}):`);
    Object.keys(store).slice(0, 20).forEach((k) => log(`  - ${k}`));
    process.exit(3);
  }

  const target = store[SESSION_KEY];
  const sessionId = target.sessionId;
  const sessionFile = target.sessionFile;
  log(`Target sessionId=${sessionId}`);
  log(`Target sessionFile=${sessionFile}`);

  // Remove entry
  delete store[SESSION_KEY];

  // Write atomically
  const tmp = `${SESSIONS_FILE}.tmp`;
  fs.writeFileSync(tmp, JSON.stringify(parent ?? store, null, 2), 'utf8');
  fs.renameSync(tmp, SESSIONS_FILE);
  log(`Removed session entry from sessions.json`);

  // Archive transcript files
  if (!fs.existsSync(ARCHIVE_DIR)) {
    fs.mkdirSync(ARCHIVE_DIR, { recursive: true });
  }
  if (sessionId) {
    const files = fs.readdirSync(SESSIONS_DIR).filter((n) => n.startsWith(sessionId));
    for (const name of files) {
      try {
        const from = path.join(SESSIONS_DIR, name);
        const to = path.join(ARCHIVE_DIR, name);
        fs.renameSync(from, to);
        log(`Archived: ${name}`);
      } catch (e) {
        log(`WARN: failed to archive ${name}: ${e.message}`);
      }
    }
  }

  log(`✅ Session reset complete. Next message will start a fresh session.`);
}

main();
